inline int edgeCount(std::vector<int> const& A, size_t N) {
    int count = 0;
    const int* data = A.data();          // raw pointer for fast indexing
    const size_t stride = N;             // row stride

    #pragma omp parallel for reduction(+:count) schedule(static)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        const int* row = data + i * stride;
        for (int j = 0; j < static_cast<int>(N); ++j) {
            if (row[j] == 1) ++count;
        }
    }
    return count;
}
