```cpp
#pragma once
#include <vector>
#include <stack>
#include <cstdint>

/* Count the number of connected components in the undirected graph defined by the
   adjacency matrix A.  A is an NxN matrix stored in row‑major order.
*/
inline void dfs_iterative(
    const std::vector<int> &A,
    int start,
    std::size_t N,
    std::vector<uint8_t> &seen)
{
    std::stack<int> st;
    st.push(start);
    seen[start] = 1;

    const int *row_start = A.data();          // stay in the same array
    while (!st.empty()) {
        int v = st.top();
        st.pop();

        // iterate over row v
        const int* row = row_start + v * N;
        for (std::size_t i = 0; i < N; ++i) {
            if (row[i] && !seen[i]) {
                seen[i] = 1;
                st.push(static_cast<int>(i));
            }
        }
    }
}

inline int componentCount(const std::vector<int> &A, std::size_t N)
{
    std::vector<uint8_t> seen(N, 0);
    int comp = 0;
    for (std::size_t v = 0; v < N; ++v) {
        if (!seen[v]) {
            dfs_iterative(A, static_cast<int>(v), N, seen);
            ++comp;
        }
    }
    return comp;
}
