/* Count the number of pixels in image with each grayscale intensity.
   The vector `image` is a grayscale image with values 0-255.
   Store the results in `bins`.
   Example:

   input: image=[2, 116, 201, 11, 92, 92, 201, 4, 2]
   output: [0, 0, 2, 0, 1, ...]
*/
inline void pixelCounts(const std::vector<int>& image,
                        std::array<std::size_t, 256>& bins)
{
    // Clear the output array
    std::fill(bins.begin(), bins.end(), 0);

    // Each thread keeps a private histogram to avoid atomics
    const int nthreads = omp_get_max_threads();
    std::vector<std::array<std::size_t,256>> local(nthreads);

    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        auto& localBins = local[tid];
        // Avoid dynamic allocation inside loop
        std::fill(localBins.begin(), localBins.end(), 0);

        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < image.size(); ++i) {
            const int v = image[i];
            localBins[v]++;  // v is guaranteed to be 0‑255
        }

        // Merge thread private bins into the global result
        for (int c = 0; c < 256; ++c) {
            #pragma omp atomic
            bins[c] += localBins[c];
        }
    }
}
