/* Vector x contains values between 0 and 100, inclusive.
   Count the number of values in [0,10), [10,20), [20,30), … and
   store the counts in `bins`. The function is fully
   deterministic and matches the original behaviour.
*/
inline void binsBy10Count(const std::vector<double>& x, std::array<std::size_t, 10>& bins)
{
    // clear output bins
    for (std::size_t j = 0; j < bins.size(); ++j) bins[j] = 0;

    // avoid repeated bounds check by using a local pointer
    const double* data = x.data();
    const std::size_t N   = x.size();

    // Parallel reduction via an array of local counters
    std::array<std::array<std::size_t, 10>, omp_get_max_threads()> local_bins{};
    #pragma omp parallel
    {
        // each thread works on its own slice
        const std::size_t stride = 1;
        const std::size_t tid = omp_get_thread_num();
        std::array<std::size_t, 10>& lb = local_bins[tid];
        for (std::size_t i = tid; i < N; i += omp_get_num_threads())
        {
            // compute bin index (valid for 0 ≤ x[i] ≤ 100)
            const std::size_t bin = static_cast<std::size_t>(data[i] / 10.0);
            ++lb[bin];
        }
    } // end parallel

    // accumulate per‑thread results into the output array
    for (unsigned t = 0; t < omp_get_max_threads(); ++t)
        for (std::size_t b = 0; b < bins.size(); ++b)
            bins[b] += local_bins[t][b];
}
