06_fft_dft:
```cpp
#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

#ifndef M_PI
#   define M_PI 3.14159265358979323846
#endif

// ---------------------------------------------------------------------
// Optimised DFT: single‑thread inner loop, parallel outer loop,
// pre‑computed twiddle factors, inlining, and reduced temporary objects.
// ---------------------------------------------------------------------
inline void dft(const std::vector<double> &x,
                std::vector<std::complex<double>> &output)
{
    const std::size_t N = x.size();
    if (N == 0) { output.clear(); return; }

    output.resize(N);

    // Pre‑compute the twiddle matrix using a single allocation.
    // Each row k holds the N complex twiddle factors for that k.
    std::vector<std::complex<double>> twiddle(N * N);
    const double two_pi_over_n = 2.0 * M_PI / N;
    for (std::size_t k = 0; k < N; ++k)
    {
        double wk = two_pi_over_n * k;
        for (std::size_t n = 0; n < N; ++n)
        {
            double angle = wk * n;           // 2πkn/N
            double c    = std::cos(angle);
            double s    = std::sin(angle);
            twiddle[k * N + n] = std::complex<double>(c, -s);
        }
    }

    // Parallel outer loop – each iteration is independent.
    #pragma omp parallel for schedule(static)
    for (std::size_t k = 0; k < N; ++k)
    {
        std::complex<double> sum(0.0, 0.0);
        const std::complex<double> *twk = &twiddle[k * N];
        for (std::size_t n = 0; n < N; ++n)
            sum += x[n] * twk[n];
        output[k] = sum;
    }
}
