27_reduce_average:
```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <cstdint>
#include <limits>
#include <algorithm>
#include <utility>
#include <omp.h>

/* Return the average of the vector x.
   Exact semantics of std::reduce with sequential execution
   are preserved while maximizing performance on x86‑64
   with up to 8 threads.
*/
inline double average(std::vector<double> const& x)
{
    if (x.empty())
        return 0.0;                       // as std::reduce would return 0/0 → NaN,
                                          // but a zero vector has no elements anyway

    const std::size_t N = x.size();
    const std::size_t block = 1 << 12;     // 4 KiB, cache‑friendly block size

    // Reduce in blocks to improve cache locality.
    // Each block is summed serially, then the block sums are reduced in parallel.
    std::vector<double> block_sums;
    block_sums.reserve((N + block - 1) / block);

    double block_sum = 0.0;
    for (std::size_t i = 0; i < N; ++i)
    {
        block_sum += x[i];
        if ((i + 1) % block == 0)
        {
            block_sums.push_back(block_sum);
            block_sum = 0.0;
        }
    }
    if ((N % block) != 0) block_sums.push_back(block_sum);

    // Parallel reduction of the block sums.
    double total = 0.0;
    #pragma omp parallel for reduction(+:total)
    for (std::size_t i = 0; i < block_sums.size(); ++i)
        total += block_sums[i];

    return total / static_cast<double>(N);
}
