#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Compute y = alpha*A*x + beta*y where alpha and beta are scalars,
   x and y are vectors, and A is a sparse matrix stored in COO format.
   x and y are length N and A is M x N. */
void spmv(double alpha, std::vector<COOElement> const& A,
          std::vector<double> const& x, double beta,
          std::vector<double>& y, size_t M, size_t N) {
    /* Scale y by beta */
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(y.size()); ++i) {
        y[static_cast<size_t>(i)] *= beta;
    }

    /* Accumulate alpha*A*x into y.
       We use atomic adds to avoid race conditions when multiple
       elements contribute to the same row. The random access pattern
       of COO makes this the simplest safe parallelisation strategy. */
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t k = 0; k < static_cast<std::ptrdiff_t>(A.size()); ++k) {
        const COOElement& a_ij = A[static_cast<size_t>(k)];
        if (a_ij.row < M && a_ij.column < N) {
            double prod = alpha * a_ij.value * x[a_ij.column];
            #pragma omp atomic
            y[a_ij.row] += prod;
        }
    }
}
