#pragma once
#include <array>
#include <vector>
#include <cstddef>
#include <omp.h>

struct Point {
    double x, y;
};

void countQuadrants(std::vector<Point> const& points, std::array<std::size_t, 4> &bins) {
    /* Zero all bins */
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    /* Per‑thread local counts to avoid contention */
    const std::size_t nthreads = std::max<std::size_t>(1, omp_get_max_threads());
    std::vector<std::array<std::size_t, 4>> local(nthreads);

    #pragma omp parallel
    {
        const std::size_t idx = omp_get_thread_num();
        std::array<std::size_t, 4> &q = local[idx];

        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < points.size(); ++i) {
            const double x = points[i].x;
            const double y = points[i].y;

            /* Use integer bitwise logic for a branch‑less decision.
               The sign bit of a double is the most significant bit of its
               IEEE‑754 representation.  Flipping a negative number with
               `x ^ 0x8000000000000000ULL` turns the sign bit to 0.  The
               result is 0 for non‑negative and 1 for negative. */
            const bool nx = std::signbit(x);
            const bool ny = std::signbit(y);

            /* Quadrant indices:
               0: +x +y
               1: -x +y
               2: -x -y
               3: +x -y
            */
            if (!nx && !ny)      ++q[0];
            else if ( nx && !ny) ++q[1];
            else if ( nx &&  ny) ++q[2];
            else                 ++q[3];
        }
    }

    /* Combine local counts into the global result */
    for (const auto &t : local) {
        bins[0] += t[0];
        bins[1] += t[1];
        bins[2] += t[2];
        bins[3] += t[3];
    }
}
