                              std::array<std::size_t, 26>& bins)
{
    // Zero the output array first
    std::fill(bins.begin(), bins.end(), 0);

    // We use a reduction on a temporary 2‑D array: one row per OpenMP thread.
    // This eliminates the need for atomic additions inside the hot loop.
    const int nthreads = omp_get_max_threads();
    std::vector<std::array<std::size_t, 26>> local_bins(nthreads);

    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < s.size(); ++i) {
        const int tid = omp_get_thread_num();
        const unsigned char c = s[i][0];          // unsigned to avoid sign‐extension
        const int idx = c - 'a';
        // The caller guarantees that s[i] is non‑empty and contains a lower‑case letter.
        local_bins[tid][idx] += 1;
    }

    // Merge thread local counts into the final result.
    for (int t = 0; t < nthreads; ++t) {
        for (int j = 0; j < 26; ++j) {
            bins[j] += local_bins[t][j];
        }
    }
}
