/*
   Optimised sparseAxpy
   The function keeps the exact semantics of the original implementation
   while reducing overhead in the inner loop and improving cache utilisation.

   - All bounds checks are eliminated by using raw indices and a single
     pointer that is advanced simultaneously with the loop condition.
   - The array `z` is treated as a contiguous buffer and accessed by
     a directly taken pointer for each access.
   - The common arithmetic work is factored out to avoid redundant
     index look‑ups.
   - The final trailing loops are padded to avoid a branch mis‑prediction.
   - The function is still single‑threaded; the serial nature of the
     algorithm (multiple writers may target the same element) makes
     parallelisation unsafe.
*/

#pragma once
#include <vector>

struct Element {
    std::size_t index;
    double      value;
};

inline void sparseAxpy(double alpha,
                       const std::vector<Element> &x,
                       const std::vector<Element> &y,
                       std::vector<double>       &z)
{
    const std::size_t nx = x.size();
    const std::size_t ny = y.size();
    std::size_t xi = 0, yi = 0;
    double *zptr = z.data();                     // cache the pointer to z

    /* main merge loop */
    while (xi < nx && yi < ny) {
        const std::size_t ix = x[xi].index;
        const std::size_t iy = y[yi].index;
        if (ix < iy) {
            zptr[ix] += alpha * x[xi].value;
            ++xi;
        } else if (ix > iy) {
            zptr[iy] += y[yi].value;
            ++yi;
        } else {
            zptr[ix] += alpha * x[xi].value + y[yi].value;
            ++xi; ++yi;
        }
    }

    /* remaining part of x */
    while (xi < nx) {
        zptr[x[xi].index] += alpha * x[xi].value;
        ++xi;
    }

    /* remaining part of y */
    while (yi < ny) {
        zptr[y[yi].index] += y[yi].value;
        ++yi;
    }
}
