/* Return the logical XOR reduction of the vector of bools x.
   Example:
   input: [false, false, false, true]
   output: true
*/
inline bool reduceLogicalXOR(std::vector<bool> const& x)
{
    bool result = false;
    // Vector<bool> stores bits packed; iterate over bits manually for speed
    const std::size_t n   = x.size();
    const std::size_t w   = sizeof(unsigned long long);
    const unsigned long long* data
        = reinterpret_cast<const unsigned long long*>(x.data());

    // process 8-byte chunks
    std::size_t i = 0;
    const std::size_t chunks = n / 64;
    for (i = 0; i < chunks; ++i) {
        unsigned long long chunk = data[i];
        // XOR the bits of this chunk into the result
        const unsigned long long parity = __builtin_parityll(chunk);
        result ^= static_cast<bool>(parity);
    }

    // process remaining bits
    for (std::size_t bit = i * 64; bit < n; ++bit) {
        result ^= static_cast<bool>(x[bit]);
    }

    return result;
}
