#pragma once
#include <vector>
#include <cstdint>
#include <cstddef>
#include <omp.h>

/* Compute the inclusive prefix sum of `x` into `output`.
 * Each element of `output[i]` is the sum of all elements
 * x[0] + ... + x[i].  The function preserves the original
 * semantics (i.e. the order of operations and resulting
 * values are identical to std::inclusive_scan under
 * GCC 12+ in release mode).
 */
inline void prefixSum(const std::vector<int64_t>& x,
                      std::vector<int64_t>& output)
{
    const std::size_t n = x.size();
    if (n == 0) return;

    output.resize(n);

    /* Choose a block size that gives about 64–128
       elements per thread for good cache behaviour.
       The block size is always a power of two so that
       the tree‑reduce algorithm is cache friendly. */
    constexpr std::size_t blockSize = 128;
    const std::size_t blockCount = (n + blockSize - 1) / blockSize;

    /* Temporary array to hold per‑block sums. */
    std::vector<int64_t> blockSums(blockCount);

    /* Stage 1 – local inclusive scan within each block */
#pragma omp parallel for schedule(static)
    for (std::size_t b = 0; b < blockCount; ++b) {
        const std::size_t start = b * blockSize;
        const std::size_t end   = std::min(start + blockSize, n);

        int64_t acc = 0;
        for (std::size_t i = start; i < end; ++i) {
            acc += x[i];
            output[i] = acc;
        }
        blockSums[b] = acc;
    }

    /* Stage 2 – prefix sum of the block sums (serial is fine) */
    int64_t acc = 0;
    for (std::size_t b = 0; b < blockCount; ++b) {
        int64_t tmp = blockSums[b];
        blockSums[b] = acc;
        acc += tmp;
    }

    /* Stage 3 – add preceding block sum to each element
       of the block (parallel). */
#pragma omp parallel for schedule(static)
    for (std::size_t b = 0; b < blockCount; ++b) {
        const std::size_t start = b * blockSize;
        const std::size_t end   = std::min(start + blockSize, n);
        const int64_t off = blockSums[b];

        for (std::size_t i = start; i < end; ++i) {
            output[i] += off;
        }
    }
}
