#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Build a sparse matrix Y (dense) from two COO matrices A and X
 *
 *   Y = A * X
 *
 * A is M×K, X is K×N.  A and X are given in COO format.
 * Y is dense, stored row‑major as a flat vector of size M*N.
 *
 * The implementation builds an auxiliary row→elements map for X,
 * then iterates over the non‑zeros of A.  For each A element it
 * multiplies the matching X elements and updates Y.  The outer
 * loop is parallelised with OpenMP.  Updates to Y are performed
 * atomically to avoid race conditions.
 */
inline void spmm(const std::vector<COOElement> &A,
                 const std::vector<COOElement> &X,
                 std::vector<double> &Y,
                 size_t M, size_t K, size_t N)
{
    Y.assign(M * N, 0.0);

    /*  Build a row‑based index for X: row → list of (column,value) pairs
     *  Using unordered_map is adequate for typical sparsity patterns.
     */
    std::unordered_map<size_t, std::vector<COOElement>> x_rows;
    x_rows.reserve(X.size() * 2);
    for (const auto &e : X) {
        x_rows[e.row].push_back(e);
    }

    /* Parallel outer loop over A's non‑zeros.
     * Atomic updates are employed since different A elements may
     * contribute to the same position in Y.
     */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < A.size(); ++i) {
        const auto &a = A[i];
        auto it = x_rows.find(a.column);
        if (it == x_rows.end()) continue;            // no match
        const auto &x_vec = it->second;
        size_t base = a.row * N;
        for (const auto &x : x_vec) {
            double prod = a.value * x.value;
            #pragma omp atomic
            Y[base + x.column] += prod;
        }
    }
}
