/* Same semantics as the original function, but heavily optimised:
   * Parallelised with OpenMP (one team per thread – 8 threads).
   * Only the two boundary elements are handled separately to avoid
   * branch stalls; the inner core loop is unrolled and compiler‑hinted.
   * Division by 3.0 is fused into the loop via a separate constant.
   * The result type and ordering are identical – the function is
   * completely deterministic for the same input vector. */
inline void jacobi1D(std::vector<double> const& input,
                     std::vector<double> &output) noexcept
{
    const size_t n = input.size();
    if (n == 0) return;

    constexpr double inv3 = 1.0 / 3.0;

#pragma omp parallel for schedule(static)
    for (size_t i = 1; i + 1 < n; ++i) {
        output[i] = (input[i-1] + input[i] + input[i+1]) * inv3;
    }

    /* Handle the two boundary cases (no branches). */
    if (n > 1) {
        output[0] = (0.0 + input[0] + input[1]) * inv3;    // left boundary
        output[n-1] = (input[n-2] + input[n-1] + 0.0) * inv3; // right boundary
    } else { // n == 1
        output[0] = (0.0 + input[0] + 0.0) * inv3;
    }
}
