struct Point {
    double x, y;
};

inline double tri_area(const Point& a, const Point& b, const Point& c) {
    // 0.5 * | cross product |
    return 0.5 * std::abs(
        a.x * (b.y - c.y) +
        b.x * (c.y - a.y) +
        c.x * (a.y - b.y));
}

/* Return the area of the smallest triangle that can be formed by any 3 points.
   Exact behavior matches the reference implementation.
*/
double smallestArea(const std::vector<Point>& points) {
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    double minArea = std::numeric_limits<double>::max();

    // Parallelise over the outer loop.  
    // Each thread keeps a local minimum to avoid contention.
    #pragma omp parallel
    {
        double localMin = std::numeric_limits<double>::max();

        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < n - 2; ++i) {
            const Point* pi = &points[i];
            for (std::size_t j = i + 1; j < n - 1; ++j) {
                const Point* pj = &points[j];
                for (std::size_t k = j + 1; k < n; ++k) {
                    const double area = tri_area(*pi, *pj, points[k]);
                    if (area < localMin) localMin = area;
                }
            }
        }

        // Reduce the per‑thread minima.
        #pragma omp atomic min
        if (localMin < minArea) minArea = localMin;
    }

    return minArea;
}
