#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* 1‑neighbored cells XOR
   – Parallelized with OpenMP (2‑level parallel for)
   – Uses pointer arithmetic for maximal cache‑line friendliness
   – Branchless count accumulation for speed
   – Keeps identical behaviour and interface
*/
void cellsXOR(std::vector<int> const& input, std::vector<int> &output, size_t N)
{
    const int* in  = input.data();
    int*        out = output.data();
    const size_t stride = N;

#pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const size_t base  = i * stride;
        const int*   up    = (i > 0)      ? in + (i - 1) * stride : nullptr;
        const int*   down  = (i + 1 < N)  ? in + (i + 1) * stride : nullptr;

        for (size_t j = 0; j < N; ++j) {
            int count = 0;
            if (up    && up   [j]    == 1) ++count;
            if (down  && down[j]    == 1) ++count;
            if (j > 0      && in   [base + j - 1] == 1) ++count;
            if (j + 1 < N  && in   [base + j + 1] == 1) ++count;
            out[base + j] = (count == 1) ? 1 : 0;
        }
    }
}
