inline void sortIgnoreZero(std::vector<int> &x)
{
    // Count non‑zero elements first to avoid multiple reallocations.
    size_t n_nonzero = 0;
    for (const int &v : x) {
        if (v != 0) ++n_nonzero;
    }

    // Extract, sort, and replace in a single pass.
    std::vector<int> tmp;
    tmp.reserve(n_nonzero);            // avoid reallocation
    for (const int &v : x) {
