// 3×3 edge‑enhancement kernel (fixed, do not change)
static constexpr int edgeKernel[3][3] = {
    {-1, -1, -1},
    {-1,  8, -1},
    {-1, -1, -1}
};

/* Convolve the edge kernel with a grayscale NxN image.
   imageIn and imageOut are row‑major flattened images.
   Uses 0 for out‑of‑bounds pixels and clamps the result to [0,255].
   Parallelized with OpenMP (static scheduling).  */
inline void convolveKernel(std::vector<int> const& imageIn,
                           std::vector<int> &imageOut,
                           size_t N) noexcept
{
    const int  stride      = static_cast<int>(N);
    const int* inPtr       = imageIn.data();
    int*       outPtr      = imageOut.data();

    // Parallel outer loop; thread work localized to contiguous rows
    #pragma omp parallel for schedule(static)
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        const int rowBase = i * stride;
        for (int j = 0; j < static_cast<int>(N); ++j) {
            int sum = 0;

            /* Unrolled 3×3 neighbourhood using integer arithmetic.
               All indices are checked only once. */
            for (int ki = -1; ki <= 1; ++ki) {
                const int ii = i + ki;
                const bool rowIn = (ii >= 0 && ii < static_cast<int>(N));
                for (int kj = -1; kj <= 1; ++kj) {
                    const int jj = j + kj;
                    if (rowIn && jj >= 0 && jj < static_cast<int>(N)) {
                        sum += inPtr[ii * stride + jj] *
                               edgeKernel[ki + 1][kj + 1];
                    }
                }
            }

            // Clamp to [0,255]
            outPtr[rowBase + j] = static_cast<int>(std::max(0, std::min(255, sum)));
        }
    }
}
