#pragma once
#include <vector>
#include <cstdlib>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   Example:

   input: A=[{0,0,1}, {0,1,1}, {1,1,-2}] b=[1,4]
   output: x=[3,-2]
*/
void solveLinearSystem(std::vector<COOElement> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N)
{
    // Create dense matrix from COO
    std::vector<double> matrix(N * N, 0.0);
    for (auto const& e : A)
        matrix[e.row * N + e.column] = e.value;

    // make copy of b
    std::vector<double> b_copy = b;

    // Gaussian elimination with partial pivoting
    for (size_t i = 0; i < N; ++i) {
        // --- Pivot search (parallel, no race)
        size_t maxRow = i;
        double maxVal = std::abs(matrix[i * N + i]);
#pragma omp parallel for schedule(static)
        for (ptrdiff_t k = i + 1; k < static_cast<ptrdiff_t>(N); ++k) {
            double val = std::abs(matrix[k * N + i]);
            if (val > maxVal) {
                // atomic to avoid race on maxVal/maxRow
#pragma omp critical
                {
                    if (val > maxVal) {
                        maxVal = val;
                        maxRow = static_cast<size_t>(k);
                    }
                }
            }
        }

        // Row swap (column‑wise)
        if (maxRow != i) {
#pragma omp parallel for schedule(static)
            for (size_t k = 0; k < N; ++k) {
                std::swap(matrix[i * N + k], matrix[maxRow * N + k]);
            }
            std::swap(b_copy[i], b_copy[maxRow]);
        }

        // Normalise pivot row (not strictly needed, but keeps numbers small)
        double pivot = matrix[i * N + i];
        if (std::abs(pivot) < 1e-15) continue; // matrix singular, skip

        double invPivot = 1.0 / pivot;
#pragma omp parallel for schedule(static)
        for (size_t k = i; k < N; ++k)
            matrix[i * N + k] *= invPivot;
        b_copy[i] *= invPivot;

        // Eliminate below
#pragma omp parallel for schedule(static)
        for (size_t k = i + 1; k < N; ++k) {
            double factor = matrix[k * N + i];
            if (factor == 0.0) continue;
            b_copy[k] -= factor * b_copy[i];
            for (size_t j = i + 1; j < N; ++j) {
                matrix[k * N + j] -= factor * matrix[i * N + j];
            }
            matrix[k * N + i] = 0.0; // explicitly zero
        }
    }

    // Back substitution
    x.resize(N);
#pragma omp parallel for schedule(static)
    for (ptrdiff_t ii = static_cast<ptrdiff_t>(N) - 1; ii >= 0; --ii) {
        size_t i = static_cast<size_t>(ii);
        double sum = 0.0;
        for (size_t j = i + 1; j < N; ++j)
            sum += matrix[i * N + j] * x[j];
        x[i] = b_copy[i] - sum;
    }
}
