   The function is O(n) on average and preserves the exact behavior
   of the original implementation (including handling of repeated values). */
int findKthSmallest(std::vector<int> const& x, int k) {
    // Defensive: ensure k is valid
    if (k < 1 || k > static_cast<int>(x.size())) {
        throw std::out_of_range("k is out of bounds");
    }

    // Work on a copy to keep the input unchanged
    std::vector<int> tmp = x;

    // nth_element guarantees that the element at position k-1 is the same
    // as if the entire container were sorted, and all elements before it
    // are <= it, those after it are >= it.
    std::nth_element(tmp.begin(), tmp.begin() + (k - 1), tmp.end());

