/* 5‑point Jacobi stencil – parallelised with OpenMP.
 *
 * Input and output are NxN grids stored row‑major.
 * The operation:
 *      output[i,j] = (input[i-1,j] + input[i+1,j] +
 *                     input[i,j-1] + input[i,j+1] +
 *                     input[i,j]) / 5
 * Boundary cells read outside the array are treated as 0, so the
 * indices that would go out of bounds contribute 0 to the sum.
 */
void jacobi2D(const std::vector<double> &input,
              std::vector<double> &output,
              size_t N) noexcept
{
    const double *in  = input.data();
    double       *out = output.data();

    /* Parallelise the double loop.  The outer loop over rows
     * is collapsed with the inner loop over columns.
     */
    #pragma omp parallel for collapse(2) schedule(static)
    for (long long i = 0; i < static_cast<long long>(N); ++i) {
        long long row_off = i * static_cast<long long>(N);
        for (long long j = 0; j < static_cast<long long>(N); ++j) {
            long long idx = row_off + j;
            double sum = in[idx];                       // self

            /* up */
            if (i > 0)            sum += in[(i - 1) * static_cast<long long>(N) + j];
            /* down */
            if (i + 1 < static_cast<long long>(N))
                                        sum += in[(i + 1) * static_cast<long long>(N) + j];
            /* left */
            if (j > 0)            sum += in[row_off + j - 1];
            /* right */
            if (j + 1 < static_cast<long long>(N))
                                        sum += in[row_off + j + 1];

            out[idx] = sum * 0.2;   // 1/5.0 pre‑multiplied
        }
    }
}
