// Compute the rank (sorted index) of each element in `x`.
// The ranks are written into `ranks_`.  The function is fully parallel
// (OpenMP enabled via <execution>), but preserves the original behaviour.
inline void ranks(std::vector<float> const& x, std::vector<std::size_t>& ranks_) {
    const std::size_t n = x.size();
    ranks_.resize(n);

    // Pair each value with its original index.
    std::vector<std::pair<float, std::size_t>> data;
    data.reserve(n);
    for (std::size_t i = 0; i < n; ++i) data.emplace_back(x[i], i);

    // Parallel sort by the value component using the default parallel policy.
    std::sort(std::execution::par_unseq, data.begin(), data.end(),
              [](const auto& a, const auto& b) { return a.first < b.first; });

    // Assign ranks according to sorted order.
    for (std::size_t i = 0; i < n; ++i) {
        ranks_[data[i].second] = i;
    }
