/*
 * Multiply the matrix A by the vector x. Store the results in the vector y.
 * A is an MxN matrix stored in row-major, x has N elements, and y has M elements.
 *
 * Example:
 *   input:  A=[[1, -1, 2], [0, -3, 1]]  x=[2, 1, 0]
 *   output: y=[1, -3]
 *
 * The implementation keeps the exact semantics of the reference solution but
 * exploits SIMD vectorisation and multithreading for speed.
 */
inline void gemv(std::vector<double> const& A,
                 std::vector<double> const& x,
                 std::vector<double> &y,
                 size_t M, size_t N) {

    // Use the raw data pointers to enable pointer arithmetic and
    // explicit SIMD intrinsics hints for the compiler.
    const double* a = A.data();
    const double* px = x.data();
          double* py = y.data();

    // Parallelise over rows; a static schedule allows the compiler to
    // keep each thread’s cache line separate.
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < M; ++i) {
        const double* a_row = a + i * N;
        double acc = 0.0;

        // Unroll the inner loop by 4 to increase instruction‑level parallelism.
        size_t j = 0;
        for (; j + 3 < N; j += 4) {
            acc += a_row[j]   * px[j];
            acc += a_row[j+1] * px[j+1];
            acc += a_row[j+2] * px[j+2];
            acc += a_row[j+3] * px[j+3];
        }
        // Tail handling
        for (; j < N; ++j) {
            acc += a_row[j] * px[j];
        }

        py[i] = acc;
    }
}
