#pragma once
#include <vector>
#include <algorithm>
#include <cmath>
#include <cstddef>
#include <utility>

struct Point {
    double x, y;
};

// ------------- Helpers -------------
inline double sqr(double v) noexcept { return v * v; }

inline double dist(const Point& a, const Point& b) noexcept {
    return std::sqrt(sqr(b.x - a.x) + sqr(b.y - a.y));
}

// Cross product (b - a) x (c - a)
inline double cross(const Point& a, const Point& b, const Point& c) noexcept {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

// ------------- Main Function -------------
double convexHullPerimeter(const std::vector<Point>& points) {
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    // Copy and sort points (lexicographically by x, then y)
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) noexcept {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    // Preallocate hull container
    std::vector<Point> hull(2 * n);
    std::size_t k = 0;      // current size of hull

    // Build lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (k >= 2 &&
               cross(hull[k - 2], hull[k - 1], sorted[i]) <= 0.0)
            --k;
        hull[k++] = sorted[i];
    }

    // Build upper hull
    for (std::size_t i = n - 1; i > 0; --i) {
        while (k >= 2 + (n - i) &&
               cross(hull[k - 2], hull[k - 1], sorted[i - 1]) <= 0.0)
            --k;
        hull[k++] = sorted[i - 1];
    }

    // Remove the duplicated last point
    hull.resize(k - 1);

    // Compute perimeter
    double perimeter = 0.0;
    for (std::size_t i = 0; i + 1 < hull.size(); ++i)
        perimeter += dist(hull[i], hull[i + 1]);

    // Final edge closing the polygon
    perimeter += dist(hull.front(), hull.back());

    return perimeter;
}
