/*  Return the vertices of the convex hull in counter‐clockwise order.
 *  The algorithm is a standard monotone chain (Andrew’s) algorithm.
 *  The implementation trades a bit of memory for speed:
 *  - Points are copied only once into a sorted buffer.
 *  - The hull is constructed in a pre‑allocated array and moved to `hull`.
 *  - The cross product is inlined and uses a simple struct for pairs.   */
void convexHull(const std::vector<Point>& points, std::vector<Point>& hull)
{
    // Small input: copy directly
    const size_t n = points.size();
    if (n < 3)
    {
        hull.assign(points.begin(), points.end());
        return;
    }

    // Copy and sort all input points
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b)
              {
                  return (a.x < b.x) || (a.x == b.x && a.y < b.y);
              });

    // Pre‑allocate scratch buffer large enough for lower+upper hull
    std::vector<Point> buf;
    buf.resize(2 * n);          // at most 2*n points
    std::size_t k = 0;          // current hull size

    auto cross = [](const Point& o, const Point& a, const Point& b) -> double
    {
        return (a.x - o.x) * (b.y - o.y) - (a.y - o.y) * (b.x - o.x);
    };

    // Build lower hull
    for (size_t i = 0; i < n; ++i)
    {
        while (k >= 2 && cross(buf[k - 2], buf[k - 1], sorted[i]) <= 0) --k;
        buf[k++] = sorted[i];
    }

    // Build upper hull (skip first and last point already in lower hull)
    for (size_t i = n - 1; i > 0; --i)
    {
        while (k >= n + 1 && cross(buf[k - 2], buf[k - 1], sorted[i - 1]) <= 0) --k;
        buf[k++] = sorted[i - 1];
    }

    // `k-1` removes the duplicate starting point
    hull.resize(k - 1);
    std::memcpy(hull.data(), buf.data(), (k - 1) * sizeof(Point));
}
