#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <omp.h>

/*  An almost‑pure‑radix‑2 FFT implementation that preserves the
    semantics of the original code while providing significant speed
    improvements on a modern 8‑thread x86‑64 target.  The algorithm
    performs the DFT in the usual Cooley–Tukey fashion, uses an
    in‑place butterfly, pre‑computes the twiddle factors once per
    stage, and parallelises the butterfly loops with OpenMP.  The
    resulting real and imaginary parts are written into 'r' and 'i'. */
static inline void fft(const std::vector<std::complex<double>> &x,
                       std::vector<double> &r,
                       std::vector<double> &i)
{
    const size_t N = x.size();
    if (N == 0) return;

    /* --------- local copy of the input (in-place FFT) --------- */
    std::vector<std::complex<double>> c(x);

    /* --------- bit‑reversal re‑ordering (in‑place) --------- */
    size_t n = N;
    size_t m = 1;
    while ((m << 1) < n) m <<= 1;               // greatest power of two <= N

    for (size_t i = 0; i < n; ++i) {
        size_t j = i;
        j = (((j & 0xaaaaaaaa) >> 1) | ((j & 0x55555555) << 1));
        j = (((j & 0xcccccccc) >> 2) | ((j & 0x33333333) << 2));
        j = (((j & 0xf0f0f0f0) >> 4) | ((j & 0x0f0f0f0f) << 4));
        j = (((j & 0xff00ff00) >> 8) | ((j & 0x00ff00ff) << 8));
        j = ((j >> 16) | (j << 16)) >> (32 - (int)std::log2(n));
        if (j > i) std::swap(c[i], c[j]);
    }

    /* --------- iterative Radix‑2 butterfly in-place  --------- */
    for (size_t s = 1; s <= (size_t)std::log2(n); ++s) {
        const size_t m = 1 << s;          // stage width
        const size_t half = m >> 1;
        const double theta = -2 * M_PI / (double)m;
        /* precompute twiddle factors for this stage */
        std::vector<std::complex<double>> w(half);
        w[0] = {1.0, 0.0};
        const std::complex<double> wm{std::cos(theta), std::sin(theta)};
        for (size_t k = 1; k < half; ++k)
            w[k] = w[k-1] * wm;

        /* each thread handles a set of “groups” of butterflies */
        #pragma omp parallel for schedule(static)
        for (size_t k = 0; k < n; k += m) {
            for (size_t j = 0; j < half; ++j) {
                const size_t idx = k + j;
                const size_t idx2 = idx + half;
                const std::complex<double> t = w[j] * c[idx2];
                c[idx2] = c[idx] - t;
                c[idx] += t;
            }
        }
    }

    /* --------- final real/imaginary output  --------- */
    for (size_t j = 0; j < n; ++j) {
        r[j] = c[j].real();
        i[j] = c[j].imag();
    }
}
