#pragma once
#include <limits>
#include <vector>
#include <omp.h>

/* Replace the i‑th element of the vector x with the minimum value from indices 0 through i.
   Examples:
   input:  [8, 6, -1, 7, 3, 4, 4]
   output: [8, 6, -1, -1, -1, -1, -1]
   input:  [5, 4, 6, 4, 3, 6, 1, 1]
   output: [5, 4, 4, 4, 3, 3, 1, 1]
*/
inline void partialMinimums(std::vector<float> &x) {
    const size_t n = x.size();
    if (n == 0) return;

    const int n_threads = omp_get_max_threads();
    const size_t chunk = (n + n_threads - 1) / n_threads;

    // 1) compute local minima for each chunk
    std::vector<float> local_min(n_threads, std::numeric_limits<float>::max());
#pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const size_t start = tid * chunk;
        const size_t end   = std::min(start + chunk, n);

        float best = std::numeric_limits<float>::max();
        for (size_t i = start; i < end; ++i) {
            best = std::min(best, x[i]);
        }
        local_min[tid] = best;
    }

    // 2) prefix scan of local minima to get the minimal value up to the start of each chunk
    std::vector<float> pref_min(n_threads);
    float acc = std::numeric_limits<float>::max();
    for (int i = 0; i < n_threads; ++i) {
        acc = std::min(acc, local_min[i]);
        pref_min[i] = acc;
    }

    // 3) apply the minimal prefix to each element
#pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const size_t start = tid * chunk;
        const size_t end   = std::min(start + chunk, n);

        // minimal value before this chunk
        float cur = (tid == 0)
                        ? std::numeric_limits<float>::max()
                        : pref_min[tid - 1];

        for (size_t i = start; i < end; ++i) {
            cur = std::min(cur, x[i]);  // prefix min up to i
            x[i] = cur;
        }
    }
}
