/**
 * Compute the forward FFT of a power‑of‑two sized vector `x`.
 * The routine is only defined for `x.size()` being a power of two.
 * The result is written into `output`.  The function preserves the
 * exact numerical behaviour of the reference implementation.
 *
 * The implementation below follows the iterative radix‑2 Cooley–Tukey
 * algorithm.  The butterfly stages and the final bit‑reversal are
 * parallelised with OpenMP.
 */
void fft(std::vector<std::complex<double>> const& x,
         std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output = x;                     // copy input
    const std::size_t m  = static_cast<std::size_t>(std::log2(N));

    /*--- 1. Pre‑compute twiddle factors for each stage -------------------*/
    // For stage j (1 … m) we need exp(-2πi * k / 2^j) for k = 0 … 2^{j-1}-1
    std::vector<std::vector<std::complex<double>>> twiddles(m);
    for (std::size_t j = 0; j < m; ++j) {
        std::size_t half   = 1u << j;          // 2^{j-1}
        std::size_t len    = 1u << (j + 1);    // 2^j
        auto& T = twiddles[j];
        T.resize(half);
        const double angle = -M_PI / static_cast<double>(half); // -π / 2^{j-1}
        for (std::size_t k = 0; k < half; ++k) {
            T[k] = std::polar(1.0, angle * static_cast<double>(k)); // exp(-i*angle*k)
        }
    }

    /*--- 2. Butterfly stages (radix‑2) ---------------------------------*/
    for (std::size_t s = 0; s < m; ++s) {
        const std::size_t step   = 1u << (s + 1);          // 2^s * 2
        const std::size_t half   = step >> 1;              // 2^s
        const auto& T = twiddles[s];

        /* Parallelise the loop over the whole input.  Each butterfly
           is independent, so we can chunk the work. */
        #pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; i += step) {
            for (std::size_t j = 0; j < half; ++j) {
                const std::size_t k  = i + j;
                const std::size_t l  = k + half;
                const std::complex<double> t = output[l] * T[j];
                output[l] = output[k] - t;
                output[k] += t;
            }
        }
    }

    /*--- 3. Bit‑reversal permutation -----------------------------------*/
    // Because the data is already in natural order after the stages,
    // we just need to swap elements whose indices are bit‑reverses.
    const std::size_t bits = m;
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t rev = 0;
        std::size_t x = i;
        for (std::size_t b = 0; b < bits; ++b) {
            rev = (rev << 1) | (x & 1);
            x >>= 1;
        }
        if (rev > i) {
            std::swap(output[i], output[rev]);
        }
    }
}
