#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Factorize the matrix A into A = LU (in‑place) where L is lower
   triangular with unit diagonal and U is upper triangular.
   The matrix is stored in row‑major order.
   The algorithm is the textbook Doolittle LU without pivoting. */
inline void luFactorize(std::vector<double> &A, size_t N)
{
    const size_t inc = N;               // row stride
    const double *restrict a = A.data(); // constant pointer to data

    /* Each step k modifies rows i > k.
       The outer loop stays sequential, but the inner row loop can be
       parallelized safely because each row i is independent. */
    for (size_t k = 0; k < N; ++k) {
        const size_t kRow = k * inc;
        const double pivot = a[kRow + k];       // A[k][k]
        const double *restrict kRowPtr = a + kRow;

        /* Parallel over rows i > k */
#pragma omp parallel for schedule(static)
        for (size_t i = k + 1; i < N; ++i) {
            size_t iRow = i * inc;
            double *restrict iRowPtr = &A[iRow];

            /* Compute the multiplier for element (i,k) */
            const double factor = A[iRow + k] / pivot;
            iRowPtr[k] = factor;                 // store L[i][k]

            /* Update the remainder of the row: A[i][j] -= factor * A[k][j]  */
            double *restrict dst = iRowPtr + k + 1;
            const double *restrict src = kRowPtr + k + 1;
            size_t remaining = N - k - 1;
            /* Unroll 4 terms for performance */
            for (; remaining >= 4; remaining -= 4) {
                dst[0] -= factor * src[0];
                dst[1] -= factor * src[1];
                dst[2] -= factor * src[2];
                dst[3] -= factor * src[3];
                dst += 4;
                src += 4;
            }
            /* Tail loop for the remaining elements */
            for (; remaining > 0; --remaining, ++dst, ++src) {
                *dst -= factor * (*src);
            }
        }
    }
}
