    #pragma omp declare reduction(\
        min_pair : std::pair<double,size_t> : \
        omp_out = (omp_in.first < omp_out.first ? omp_in : omp_out))

    // Initialise with the first element
    std::pair<double,size_t> best{ std::abs(x[0] - M_PI), 0 };

    // Parallel reduction using the custom type
    #pragma omp parallel for reduction(min_pair:best)
    for (size_t i = 1; i < x.size(); ++i) {
        double d = std::abs(x[i] - M_PI);
        if (d < best.first) {
            best = { d, i };
        }
    }

    return best.second;
}
