#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major. x and b have N elements.
   Example:

   input: A=[[1,4,2], [1,2,3], [2,1,3]] b=[11, 11, 13]
   output: x=[3, 1, 2]
*/
static inline void solveLinearSystem(const std::vector<double> &A,
                                     const std::vector<double> &b,
                                     std::vector<double> &x,
                                     size_t N)
{
    // Make mutable copies
    std::vector<double> A_copy(A);
    std::vector<double> b_copy(b);

    // Gaussian elimination with OpenMP for parallel elimination of rows
    for (size_t i = 0; i < N - 1; ++i) {
        const double pivot = A_copy[i * N + i];
        if (pivot == 0.0)                      // Singular matrix – abort
            return;

        // Parallel elimination of the rows below pivot
        #pragma omp parallel for schedule(static)
        for (size_t j = i + 1; j < N; ++j) {
            const double factor = A_copy[j * N + i] / pivot;
            if (factor == 0.0) continue;
            double *row_j = &A_copy[j * N];
            const double *row_i = &A_copy[i * N];
            // First element (k==i) can be clobbered to zero
            row_j[i] -= factor * row_i[i];

            // Vectorized update of the remaining columns
            #pragma omp simd
            for (size_t k = i + 1; k < N; ++k)
                row_j[k] -= factor * row_i[k];

            b_copy[j] -= factor * b_copy[i];
        }
    }

    // Back substitution (sequential – one thread is enough)
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        for (size_t j = i + 1; j < N; ++j)
            sum += A_copy[i * N + j] * x[j];
        x[i] = (b_copy[i] - sum) / A_copy[i * N + i];
    }
}
