#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Multiply the matrix A by the matrix B. Store the results in the matrix C.
   A is an MxK matrix, B is a KxN matrix, and C is a MxN matrix. The matrices are stored in row‑major.
   Example:
   input: A=[[1, -1, 2], [0, -2, 1]] B=[[4, 1], [-1, 0], [2, 2]]
   output: C=[[9, 5], [4, 2]]
*/
inline void gemm(std::vector<double> const& A,
                 std::vector<double> const& B,
                 std::vector<double> &C,
                 size_t M, size_t K, size_t N)
{
    // Simple tiling: 64x64 is a good compromise for most cache sizes
    constexpr size_t TILE_M = 64;
    constexpr size_t TILE_K = 64;
    constexpr size_t TILE_N = 64;

    // Parallelise over the outermost block dimension (rows of C)
    #pragma omp parallel for schedule(static)
    for (size_t ii = 0; ii < M; ii += TILE_M) {
        size_t i_max = std::min(ii + TILE_M, M);
        for (size_t kk = 0; kk < K; kk += TILE_K) {
            size_t k_max = std::min(kk + TILE_K, K);
            for (size_t jj = 0; jj < N; jj += TILE_N) {
                size_t j_max = std::min(jj + TILE_N, N);

                // Work on a sub‑matrix C[ii: i_max, jj: j_max]
                for (size_t i = ii; i < i_max; ++i) {
                    double* c_row = &C[i * N + jj];
                    const double* a_row = &A[i * K + kk];
                    for (size_t k = kk; k < k_max; ++k) {
                        double a_val = a_row[k - kk];
                        const double* b_row = &B[k * N + jj];
                        for (size_t j = jj; j < j_max; ++j) {
                            // C[i][j] += A[i][k] * B[k][j];
                            c_row[j - jj] += a_val * b_row[j - jj];
                        }
                    }
                }
            }
        }
    }
}
