#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <omp.h>

/* ------------------------------------------------------------------
   Optimised FFT for real‑to‑complex conjugate operation.
   ------------------------------------------------------------------ */
inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    const std::size_t N = x.size();
    if (N < 2) return;                         // no-op for trivial size
    const std::size_t LOGN = static_cast<std::size_t>(std::log2(static_cast<double>(N)));

    /* ---------------------------------------------------------------
       1) Pre‑compute twiddle factors (radix‑2).
       --------------------------------------------------------------- */
    std::vector<std::complex<double>> twiddles( N >> 1 );
    const double pi = 3.141592653589793238462643383279502884L;
    for (std::size_t i = 0; i < twiddles.size(); ++i)
        twiddles[i] = std::polar( 1.0, -2.0 * pi * i / N );

    /* ---------------------------------------------------------------
       2) Bit‑reversal permutation using a small lookup table.
       --------------------------------------------------------------- */
    constexpr std::size_t BITS_PER_BYTE = 8;
    constexpr std::size_t BYTE_MASK      = 0xFF;
    std::uint32_t revB[256];
    for (std::size_t b = 0; b < 256; ++b) {
        std::uint32_t v = static_cast<std::uint32_t>(b);
        v = (v & 0xAA) >> 1 | (v & 0x55) << 1;
        v = (v & 0xCC) >> 2 | (v & 0x33) << 2;
        v = (v & 0xF0) >> 4 | (v & 0x0F) << 4;
        revB[b] = v;
    }

    std::vector<std::size_t> perm(N);
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t rev = 0;
        for (int b = 0; b < static_cast<int>(LOGN); ++b)
            rev = (rev << 8) | revB[(i >> (b * BITS_PER_BYTE)) & BYTE_MASK];
        perm[i] = rev >> (32 - LOGN);
    }

    /* Apply bit‑reversal in parallel */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = perm[i];
        if (j > i) std::swap(x[i], x[j]);
    }

    /* ---------------------------------------------------------------
       3) Cooley–Tukey radix‑2 Danielson–Lanczos.
          Parallelise over the outer butterfly stages.
       --------------------------------------------------------------- */
    for (std::size_t stage = 1; stage <= LOGN; ++stage) {
        std::size_t step   = 1U << stage;           // size of sub‑FFT
        const std::size_t half = step >> 1;
        const std::size_t twiddle_factor = N / step;

        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < half; ++k) {
            const std::complex<double> W = twiddles[ k * twiddle_factor ];
            for (std::size_t j = k; j < N; j += step) {
                std::size_t l = j + half;
                std::complex<double> t = x[j] - x[l];
                x[j] += x[l];
                x[l] = t * W;
            }
        }
    }

    /* ---------------------------------------------------------------
       4) Conjugate the result (exactly as original spec).
       --------------------------------------------------------------- */
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);
}
