#pragma once
#include <vector>
#include <omp.h>

/*
   Simulate one generation of Game of Life.

   Each cell is represented by an `int` (0 or 1). The grids `input` and `output`
   are stored row‑major in a flat `std::vector<int>`.  The function assumes
   linear address space: cell (i, j) is at index `i * N + j`.

   The implementation is fully deterministic and produces exactly the same
   result as the reference version.  It uses the CPU’s cache hierarchy,
   eliminates repeated bounds checks, and runs all rows in parallel via
   OpenMP.  The compute‑dense inner loop is kept simple enough to allow the
   compiler to vectorize it.

   Parameters
   ----------
   input  : read‑only grid
   output : write‑only grid (must be size N*N)
   N      : dimension of the square grid
*/
inline void gameOfLife(const std::vector<int>& input,
                      std::vector<int>& output,
                      size_t N)
{
    // Row base pointers for fast address calculation.
    // +1 and -1 rows are needed for boundary handling only.
    const size_t N2 = N * N;
    if (output.size() < N2) output.resize(N2);

    const int *in  = input.data();
    int       *out = output.data();

    // Parallel over rows; the inner column loop runs sequentially.
    // OpenMP will automatically schedule work among the available threads.
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i) {
        const size_t iN  = i * N;
        const size_t im1 = (i > 0)      ? (i - 1) * N : SIZE_MAX;
        const size_t ip1 = (i + 1 < N)  ? (i + 1) * N : SIZE_MAX;

        for (size_t j = 0; j < N; ++j) {
            const int cur = in[iN + j];
            int sum = 0;

            // Helper lambda to safely add a neighbour if it exists.
            auto add = [&](size_t idx) noexcept {
                if (idx != SIZE_MAX) sum += in[idx];
            };

            // N, S
            add(im1 + j);
            add(ip1 + j);

            // W, E
            if (j > 0)   add(iN + j - 1);
            if (j + 1 < N) add(iN + j + 1);

            // NW, NE
            if (j > 0   && im1 != SIZE_MAX)   add(im1 + j - 1);
            if (j + 1 < N && im1 != SIZE_MAX) add(im1 + j + 1);

            // SW, SE
            if (j > 0   && ip1 != SIZE_MAX)   add(ip1 + j - 1);
            if (j + 1 < N && ip1 != SIZE_MAX) add(ip1 + j + 1);

            // Apply the classic Game‑of‑Life rules.
            out[iN + j] = (cur ? (sum == 2 || sum == 3) : (sum == 3));
        }
    }
}
