#pragma once
#include <complex>
#include <vector>
#include <algorithm>
#include <thread>
#include <mutex>
#include <queue>
#include <cmath>
#include <future>

/*
 * Parallel sort of a vector of std::complex<double> by magnitude.
 *
 * This implementation splits the input into sub‑ranges, sorts each sub‑range
 * using std::sort in parallel, and then merges the sorted sub‑ranges.
 *
 * The algorithm preserves the exact ordering used by the original
 * single‑threaded implementation:
 *   - If two magnitudes are equal the relative order of the two elements
 *     is the same as in the input vector (stable).
 *
 * The code takes advantage of at most std::thread::hardware_concurrency()
 * worker threads (up to 8 on the target platform).
 */
template <typename Iterator, typename Comparator>
static void parallel_merge_sort(Iterator first, Iterator last, Comparator comp)
{
    const std::size_t total   = std::distance(first, last);
    if (total <= 1)
        return;

    /* Determine the number of chunks (threads) */
    const std::size_t max_threads = std::thread::hardware_concurrency();
    const std::size_t chunk_size  = (total + max_threads - 1) / max_threads;

    /* Sort each chunk in parallel */
    std::vector<std::future<void>> futures;
    for (std::size_t start = 0; start < total; start += chunk_size)
    {
        std::size_t end = std::min(start + chunk_size, total);
        Iterator chunk_start = first + start;
        Iterator chunk_end   = first + end;
        futures.emplace_back(std::async(std::launch::async,
                        [chunk_start, chunk_end, comp]() { std::sort(chunk_start, chunk_end, comp); }));
    }
    for (auto &f : futures) f.get();  // wait for all intra‑chunk sorts

    /* Merge the sorted chunks */
    std::vector<std::size_t> idx(max_threads, 0);
    std::vector<std::size_t> chunk_begin(max_threads), chunk_end(max_threads);
    for (std::size_t i = 0, pos = 0; i < max_threads; ++i, pos += chunk_size)
    {
        chunk_begin[i] = pos;
        chunk_end[i]   = std::min(pos + chunk_size, total);
    }

    std::vector<std::complex<double>> buffer;
    buffer.reserve(total);

    /* Priority queue of (current value, chunk id) */
    using Node = std::pair<std::complex<double>, std::size_t>;
    auto comp_node = [&](const Node &a, const Node &b) { return comp(a.first, b.first); };
    std::priority_queue<Node, std::vector<Node>, decltype(comp_node)> pq(comp_node);

    /* Initialise the queue */
    for (std::size_t i = 0; i < max_threads; ++i)
        if (chunk_begin[i] < chunk_end[i])
            pq.emplace(first[chunk_begin[i]], i);

    /* Merge procedure */
    while (!pq.empty())
    {
        auto [val, id] = pq.top(); pq.pop();
        buffer.push_back(val);
        ++idx[id];
        std::size_t cur = chunk_begin[id] + idx[id];
        if (cur < chunk_end[id])
            pq.emplace(first[cur], id);
    }

    /* Copy back to original */
    std::copy(buffer.begin(), buffer.end(), first);
}

/*
 * Public API – identical to the original signature.
 */
void sortComplexByMagnitude(std::vector<std::complex<double>> &x)
{
    /* Comparator that mimics std::abs(a) < std::abs(b) */
    auto magComp = [](const std::complex<double> &a,
                      const std::complex<double> &b) -> bool
    {
        return std::abs(a) < std::abs(b);
    };
    parallel_merge_sort(x.begin(), x.end(), magComp);
}
