#pragma once
#include <vector>
#include <unordered_map>

struct COOElement {
   size_t row, column;
   double value;
};

/* LU factorization of a sparse NxN matrix stored in COO format.
   The result is stored row‑major in L (implicit unit diagonal) and U. */
void luFactorize(std::vector<COOElement> const& A,
                 std::vector<double>& L,
                 std::vector<double>& U,
                 size_t N)
{
    // Resize result matrices
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    /* Build a row‑wise map from the COO representation so that
       we can look up aij quickly. */
    std::vector<std::unordered_map<size_t, double>> rowVals(N);
    for (auto const& e : A) {
        rowVals[e.row][e.column] = e.value;
    }

    std::vector<double> sumU; // temporary buffer for U computation

    for (size_t i = 0; i < N; ++i) {
        // ----- Compute the i‑th row of U -----
        sumU.assign(N, 0.0);
        // Subtract L[i][k]*U[k][j] for k < i
        for (size_t k = 0; k < i; ++k) {
            double l_ik = L[i * N + k];
            if (l_ik == 0.0) continue;
            const double* Uk = &U[k * N];
            double* sU = sumU.data();
            for (size_t j = 0; j < N; ++j) {
                sU[j] -= l_ik * Uk[j];
            }
        }
        // Fill U[i][j] using the original matrix value
        for (size_t j = 0; j < N; ++j) {
            double a_ij = 0.0;
            auto it = rowVals[i].find(j);
            if (it != rowVals[i].end()) a_ij = it->second;
            U[i * N + j] = a_ij + sumU[j];
        }

        // ----- Compute the i‑th row of L (excluding the diagonal) -----
        // Use incremental accumulation of sumL[j] = sum_{k<j} L[i][k] * U[k][j]
        std::vector<double> sumL(i, 0.0);
        for (size_t j = 0; j < i; ++j) {
            if (j > 0) {
                sumL[j] = sumL[j - 1] + L[i * N + (j - 1)] * U[(j - 1) * N + j];
            }
            // a_ij could be zero if not stored
            double a_ij = 0.0;
            auto it = rowVals[i].find(j);
            if (it != rowVals[i].end()) a_ij = it->second;

            double denom = U[j * N + j];
            // U[j][j] is guaranteed non‑zero for a valid LU
            L[i * N + j] = (a_ij - sumL[j]) / denom;
        }

        // Implicit unit diagonal
        L[i * N + i] = 1.0;
    }
}
